const ALLIANCE_UPLOAD_WEBHOOK = process.env.DISCORD_UPLOAD_WEBHOOK
  || 'https://discord.com/api/webhooks/1434658170500022282/x4bEXDmiS3BLc_mlyS6olqv68i3FpSxTo_OHHBbmiH4FHr01Q_iJeexf-ZV53vZUdcxC';
function notifyDiscord(msg) {
  const url = ALLIANCE_UPLOAD_WEBHOOK;
  if (!url) { console.log('[DISCORD] no webhook set'); return; }
  try {
    const body = JSON.stringify({ content: msg });
    const u = new URL(url);
    const req = https.request({
      hostname: u.hostname,
      path: u.pathname + u.search,
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body) }
    });
    req.on('error', e => console.error('[DISCORD] notify error:', e.message));
    req.write(body);
    req.end();
  } catch(e) { console.error('[DISCORD] notify failed:', e.message); }
}
function awstStamp(iso) {
  try {
    return new Date(iso).toLocaleString('en-AU', {
      timeZone: 'Australia/Perth', hour12: false,
      day: '2-digit', month: 'short', hour: '2-digit', minute: '2-digit'
    });
  } catch(e) { return iso || '?'; }
}

// ── PERSISTENT DISK STATE ─────────────────────────────────────────────────
const STATE_FILE    = '/data/state.json';
const HQ_STATE_FILE = '/data/hq-state.json';

function calcPaceFromBaseline(sv, ts) {
  const base = DEFAULT_DATA;
  if (!sv || !ts || !base.beagleSV || !base.timestamp) return null;
  const days = (new Date(ts) - new Date(base.timestamp)) / 86400000;
  if (days < 1) return null;
  const pace = (sv - base.beagleSV) / days;
  return pace >= 0.5 ? Math.round(pace * 1000) / 1000 : null;
}

function loadState() {
  try {
    if (fs.existsSync(STATE_FILE)) {
      const saved = JSON.parse(fs.readFileSync(STATE_FILE, 'utf8'));
      const calcPace = calcPaceFromBaseline(saved.beagleSV, saved.timestamp);
      if (calcPace != null) {
        console.log('[STARTUP] Recalculated beaglePace from baseline: ' + calcPace + ' (was ' + saved.beaglePace + ')');
        saved.beaglePace = calcPace;
      } else if (!saved.beaglePace || saved.beaglePace < 1.0) {
        console.log('[STARTUP] beaglePace corrupted (' + saved.beaglePace + ') — resetting to DEFAULT ' + DEFAULT_DATA.beaglePace);
        saved.beaglePace = DEFAULT_DATA.beaglePace;
      }
      console.log('[STARTUP] Loaded projections state from disk — ' + saved.timestamp);
      return saved;
    }
  } catch (e) { console.error('[STARTUP] Failed to load state:', e.message); }
  console.log('[STARTUP] No saved state — using DEFAULT_DATA');
  return { ...DEFAULT_DATA };
}

function saveState(data) {
  try { fs.writeFileSync(STATE_FILE, JSON.stringify(data), 'utf8'); }
  catch (e) { console.error('[SAVE] Failed to write projections state:', e.message); }
}

function loadHqState() {
  try {
    if (fs.existsSync(HQ_STATE_FILE)) {
      const saved = JSON.parse(fs.readFileSync(HQ_STATE_FILE, 'utf8'));
      console.log('[STARTUP] Loaded HQ state from disk — ' + (saved.players?.length ?? 0) + ' players');
      return saved;
    }
  } catch (e) { console.error('[STARTUP] Failed to load HQ state:', e.message); }
  return { timestamp: null, uploader: null, alliancePace: null, airlines: 0, players: [], history: [] };
}

function saveHqState(data) {
  try { fs.writeFileSync(HQ_STATE_FILE, JSON.stringify(data), 'utf8'); }
  catch (e) { console.error('[SAVE] Failed to write HQ state:', e.message); }
}


