const FUEL_PATH_FILE = '/data/fuel-path.json';

function generateFuelPath() {
  const now = new Date();
  const year = now.getUTCFullYear();
  const month = now.getUTCMonth() + 1;
  const daysInMonth = new Date(year, month, 0).getDate();
  const days = [];
  for (let d = 1; d <= daysInMonth; d++) {
    const daySchedule = FUEL_SCHEDULE[String(d)];
    if (!daySchedule) {
      days.push({ day: d, fuel: null, co2: null });
      continue;
    }
    let bestFuel = null, bestCo2 = null;
    for (const [slot, [fp, cp]] of Object.entries(daySchedule)) {
      if (!bestFuel || fp < bestFuel.price) bestFuel = { slot, price: fp };
      if (!bestCo2 || cp < bestCo2.price) bestCo2 = { slot, price: cp };
    }
    const fuelRating = bestFuel.price < 500 ? 'green' : bestFuel.price <= 900 ? 'amber' : 'red';
    const co2Rating = bestCo2.price < 120 ? 'green' : bestCo2.price <= 160 ? 'amber' : 'red';
    days.push({
      day: d,
      fuel: { slot: bestFuel.slot, price: bestFuel.price, rating: fuelRating },
      co2:  { slot: bestCo2.slot,  price: bestCo2.price,  rating: co2Rating }
    });
  }
  return { year, month, generated: now.toISOString(), days };
}

function getFuelPath() {
  const now = new Date();
  const curMonth = now.getUTCMonth() + 1;
  const curYear = now.getUTCFullYear();
  try {
    if (fs.existsSync(FUEL_PATH_FILE)) {
      const cached = JSON.parse(fs.readFileSync(FUEL_PATH_FILE, 'utf8'));
      if (cached.month === curMonth && cached.year === curYear) return cached;
    }
  } catch (e) { console.error('[FUEL-PATH] Cache read error:', e.message); }
  const fp = generateFuelPath();
  try {
    if (!fs.existsSync('/data')) fs.mkdirSync('/data', { recursive: true });
    fs.writeFileSync(FUEL_PATH_FILE, JSON.stringify(fp), 'utf8');
    console.log('[FUEL-PATH] Generated for ' + curYear + '-' + String(curMonth).padStart(2,'0'));
  } catch (e) { console.error('[FUEL-PATH] Write error:', e.message); }
  return fp;
}

// ── HUNTER ELITE — IN-MEMORY STORE ────────────────────────────────────────
const HUNTER_FILE = path.join(__dirname, 'data', 'hunter-data.json');
let hunterStore = {
  lastUpdated: null,
  players: {},
  alliances: [],
  individuals: []
};

try {
  if (!fs.existsSync(path.join(__dirname, 'data')))
    fs.mkdirSync(path.join(__dirname, 'data'), { recursive: true });
  if (fs.existsSync(HUNTER_FILE))
    hunterStore = JSON.parse(fs.readFileSync(HUNTER_FILE, 'utf8'));
} catch (e) { console.error('Hunter load error:', e); }

function saveHunter() {
  try {
    fs.writeFileSync(HUNTER_FILE, JSON.stringify(hunterStore, null, 2));
  } catch (e) {}
}

// Returns Set of Hunter-tracked player names (lowercase) to prevent data leaking
// into player-facing surfaces like HQ stats.
function getHunterTrackedNames() {
  const names = new Set();
  // From hunterData (disk-persisted format)
  if (hunterData && hunterData.players) {
    for (const p of hunterData.players) {
      if (p.airline_name) names.add(p.airline_name.toLowerCase().trim());
    }
  }
  // From hunterStore (in-memory format)
  if (hunterStore && hunterStore.players) {
    if (Array.isArray(hunterStore.players)) {
      for (const p of hunterStore.players) {
        if (p.airline_name) names.add(p.airline_name.toLowerCase().trim());
      }
    } else {
      for (const key of Object.keys(hunterStore.players)) {
        names.add(key.toLowerCase().trim());
        const p = hunterStore.players[key];
        if (p && p.airline_name) names.add(p.airline_name.toLowerCase().trim());
      }
    }
  }
  return names;
}

